func parseExecuteLoopSpec(cmd *cobra.Command, treatPassthroughAsOpaque bool) (executeloop.ExecuteLoopSpec, executeloop.DispatchOptions, error) {
	projectRoot, _ := cmd.Flags().GetString("project")
	fromRev, _ := cmd.Flags().GetString("from")
	harness, _ := cmd.Flags().GetString("harness")
	model, _ := cmd.Flags().GetString("model")
	profile, _ := cmd.Flags().GetString("profile")
	provider, _ := cmd.Flags().GetString("provider")
	labelFilter, _ := cmd.Flags().GetString("label-filter")
	effort, _ := cmd.Flags().GetString("effort")
	attemptBackend, _ := cmd.Flags().GetString("attempt-backend")
	ignoreCooldown, _ := cmd.Flags().GetBool("ignore-cooldown")
	cooldownReason, _ := cmd.Flags().GetString("reason")
	once, _ := cmd.Flags().GetBool("once")
	watch, _ := cmd.Flags().GetBool("watch")
	rawIdleInterval, _ := cmd.Flags().GetDuration("idle-interval")
	asJSON, _ := cmd.Flags().GetBool("json")
	dispatchJSON := ""
	if asJSON {
		dispatchJSON = "true"
	}
	local, _ := cmd.Flags().GetBool("local")
	noReview, _ := cmd.Flags().GetBool("no-review")
	noReviewAck, _ := cmd.Flags().GetBool("no-review-i-know-what-im-doing")
	reviewHarness, _ := cmd.Flags().GetString("review-harness")
	reviewModel, _ := cmd.Flags().GetString("review-model")
	maxCostUSD, _ := cmd.Flags().GetFloat64("max-cost")
	maxBeadCostUSD, _ := cmd.Flags().GetFloat64("max-bead-cost")
	maxRecoveryCostUSD, _ := cmd.Flags().GetFloat64("max-recovery-cost")
	preClaimTimeout, _ := cmd.Flags().GetDuration("preclaim-timeout")
	routeResolutionTimeout, _ := cmd.Flags().GetDuration("route-resolution-timeout")
	requestTimeout, _ := cmd.Flags().GetDuration("request-timeout")
	rateLimitMaxWait, _ := cmd.Flags().GetDuration("rate-limit-max-wait")
	minPower, _ := cmd.Flags().GetInt("min-power")
	maxPower, _ := cmd.Flags().GetInt("max-power")

	if noReview && !noReviewAck {
		return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--no-review requires --no-review-i-know-what-im-doing (break-glass acknowledgement)")
	}
	cooldownReason = strings.TrimSpace(cooldownReason)
	if ignoreCooldown && cooldownReason == "" {
		return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--ignore-cooldown requires --reason \"<text>\"")
	}
	if once && watch {
		return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--once and --watch are mutually exclusive")
	}
	if !watch && cmd.Flags().Changed("idle-interval") {
		return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--idle-interval only applies in watch mode; pass --watch")
	}

	mode := executeloop.ModeDrain
	var idleInterval executeloop.Duration
	if once {
		mode = executeloop.ModeOnce
	} else if watch {
		mode = executeloop.ModeWatch
		idleInterval = executeloop.Duration{Duration: rawIdleInterval}
	}

	spec := executeloop.ExecuteLoopSpec{
		ProjectRoot:            projectRoot,
		Harness:                harness,
		Model:                  model,
		Profile:                profile,
		Provider:               provider,
		LabelFilter:            labelFilter,
		Effort:                 effort,
		AttemptBackend:         attemptBackend,
		Mode:                   mode,
		IdleInterval:           idleInterval,
		NoReview:               noReview,
		ReviewHarness:          reviewHarness,
		ReviewModel:            reviewModel,
		IgnoreCooldown:         ignoreCooldown,
		CooldownOverrideReason: cooldownReason,
		OpaquePassthrough:      treatPassthroughAsOpaque,
		MaxCostUSD:             maxCostUSD,
		MaxBeadCostUSD:         maxBeadCostUSD,
		MaxRecoveryCostUSD:     maxRecoveryCostUSD,
		PreClaimTimeout:        executeloop.Duration{Duration: preClaimTimeout},
		RouteResolutionTimeout: executeloop.Duration{Duration: routeResolutionTimeout},
		RequestTimeout:         executeloop.Duration{Duration: requestTimeout},
		RateLimitMaxWait:       executeloop.Duration{Duration: rateLimitMaxWait},
		MinPower:               minPower,
		MaxPower:               maxPower,
		FromRev:                fromRev,
	}
	spec.ApplyDefaults()
	if err := spec.Validate(); err != nil {
		return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, err
	}

	return spec, executeloop.DispatchOptions{Local: local, JSON: dispatchJSON}, nil
}

func workSelfRefreshEnabled(cmd *cobra.Command) bool {
	watch, _ := cmd.Flags().GetBool("watch")
	if !watch {
		return false
	}
	// Explicit opt-out always wins: --no-self-refresh disables the capability
	// even though it is on by default in watch mode.
	if noRefresh, _ := cmd.Flags().GetBool("no-self-refresh"); noRefresh {
		return false
	}
	if cmd.Flags().Changed("self-refresh") {
		enabled, _ := cmd.Flags().GetBool("self-refresh")
		return enabled
	}
	return true
}

func executeLoopAttemptRuntime(spec executeloop.ExecuteLoopSpec, output io.Writer, events agent.BeadEventAppender, runner agent.AgentRunner, checker agent.ExecutionResourceChecker, beadStoreRoot string) agent.ExecuteBeadRuntime {
	return agent.ExecuteBeadRuntime{
		FromRev:          spec.FromRev,
		Output:           output,
		BeadStoreRoot:    beadStoreRoot,
		BeadEvents:       events,
		AgentRunner:      runner,
		ResourceChecker:  checker,
		RateLimitMaxWait: spec.RateLimitMaxWait.Duration,
	}
}

func optionalIntFlag(cmd *cobra.Command, name string, defaultValue int) int {
	if cmd.Flags().Lookup(name) == nil {
		return defaultValue
	}
	value, err := cmd.Flags().GetInt(name)
	if err != nil {
		return defaultValue
	}
	return value
}

func optionalFloat64Flag(cmd *cobra.Command, name string, defaultValue float64) float64 {
	if cmd.Flags().Lookup(name) == nil {
		return defaultValue
	}
	value, err := cmd.Flags().GetFloat64(name)
	if err != nil {
		return defaultValue
	}
	return value
}

func (f *CommandFactory) runAgentExecuteLoopImpl(cmd *cobra.Command, treatPassthroughAsOpaque bool, tryTargetBeadID string) error {
	spec, dispatch, err := parseExecuteLoopSpec(cmd, treatPassthroughAsOpaque)
	if err != nil {
		return err
	}
	projectFlag := spec.ProjectRoot
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	spec.ProjectRoot = projectRoot
	beadStoreRoot := f.commandBeadStoreRoot(projectFlag, projectRoot)
	if tryTargetBeadID != "" {
		spec.Mode = executeloop.ModeOnce
		spec.IdleInterval = executeloop.Duration{}
	}
	spec.Profile = agent.NormalizeRoutingProfile(spec.Profile)

	noRoutingFlags := spec.Harness == "" && spec.Model == "" && spec.Provider == "" &&
		spec.Profile == "" && spec.MinPower == 0 &&
		spec.MaxPower == 0 && !cmd.Flags().Changed("harness") &&
		!cmd.Flags().Changed("model") && !cmd.Flags().Changed("provider") &&
		!cmd.Flags().Changed("profile") &&
		!cmd.Flags().Changed("min-power") && !cmd.Flags().Changed("max-power")
	hasProjectRoutingConfig := projectHasRoutingConfig(projectRoot)
	autoInferPowerClass := noRoutingFlags && !hasProjectRoutingConfig

	store := bead.NewStore(beadStoreRoot)
	workerStore := agent.ExecuteBeadLoopStore(store)
	if spec.IgnoreCooldown {
		workerStore = newIgnoreCooldownStore(store)
	}
	jsonOutput := dispatch.JSON == "true"
	cleanupLog := cmd.ErrOrStderr()
	if jsonOutput {
		cleanupLog = io.Discard
	}
	cleanupRunner := newStartupHousekeepingRunner(projectRoot)
	if tryTargetBeadID == "" && spec.Mode != executeloop.ModeWatch {
		if breakdown, bErr := store.ReadyExecutionBreakdown(); bErr != nil {
			return bErr
		} else if len(breakdown.ExecutionReady) == 0 && len(breakdown.RetryCooldown) == 0 {
			if _, cleanupErr := cleanupRunner.Cleanup(cmd.Context()); cleanupErr != nil {
				return cleanupErr
			}
			return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, agent.NewNoReadyWorkLoopResult(spec.Mode, breakdown), jsonOutput)
		}
	}

	loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
	loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
	_ = os.MkdirAll(loopLogDir, 0o755)
	loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
	var loopSink io.Writer
	if lf, err := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); err == nil {
		loopSink = lf
		defer lf.Close() //nolint:errcheck
	}

	probeIdent := workerprobe.Identity{
		ProjectRoot:  projectRoot,
		Harness:      spec.Harness,
		Model:        spec.Model,
		ExecutorPID:  os.Getpid(),
		ExecutorHost: hostnameOrEmpty(),
		StartedAt:    time.Now().UTC(),
	}
	probe := workerprobe.New(probeIdent, workerprobe.Config{AddrFunc: serverpkg.ReadServerAddr})
	probeCtx, probeCancel := context.WithCancel(context.Background())
	probe.Start(probeCtx)
	defer func() {
		probeCancel()
		probe.Stop()
	}()
	if loopSink != nil {
		loopSink = workerprobe.TeeJSONL(loopSink, probe)
	} else {
		loopSink = workerprobe.TeeJSONL(io.Discard, probe)
	}

	localCoord := serverpkg.NewLocalLandCoordinator(projectRoot, agent.RealLandingGitOps{})
	defer localCoord.Stop()

	var reviewer agent.BeadReviewer
	if !spec.NoReview {
		reviewer = &agent.DefaultBeadReviewer{
			ProjectRoot: projectRoot,
			BeadStore:   bead.NewStore(beadStoreRoot),
			BeadEvents:  bead.NewStore(beadStoreRoot),
			Harness:     spec.ReviewHarness,
			Model:       spec.ReviewModel,
		}
	}

	overrides := config.CLIOverrides{
		Assignee:          resolveClaimAssignee(),
		Harness:           spec.Harness,
		Model:             spec.Model,

	workerLog := runtime.Log
	prevTrackerSink := SetTrackerLockMetricsSink(func(s TrackerLockSample) {
		emit("loop.tracker_lock", map[string]any{
			"section": s.Section,
			"wait_ms": s.Wait.Milliseconds(),
			"hold_ms": s.Hold.Milliseconds(),
			"retries": s.Retries,
		})
		if workerLog != nil {
			_, _ = fmt.Fprintf(workerLog, "tracker_lock section=%s wait=%s hold=%s retries=%d\n",
				s.Section, s.Wait.Round(time.Millisecond), s.Hold.Round(time.Millisecond), s.Retries)
		}
	})
	defer func() { SetTrackerLockMetricsSink(prevTrackerSink) }()

	claimSuccessRateWindowSize := runtime.effectiveClaimSuccessRateWindow()
	claimSuccessRateThreshold := runtime.effectiveClaimSuccessRateThreshold()
	claimSuccessRateWindow := make([]bool, 0, claimSuccessRateWindowSize)
	claimSuccessRateSuccesses := 0
	claimSuccessRateWarned := false
	preClaimWarnThreshold := runtime.effectivePreClaimWarnRepeatThreshold()
	preClaimWarnState := preClaimWarnRepeatState{}
	// exitReason is populated as the loop exits to surface a structured reason
	// in the loop.end event (ddx-dc157075 AC #4). Work-owned terminal reasons
	// are classified through work.StopCondition; fatal_config,
	// preflight_failed, resource_exhausted, and future provider exhaustion are
	// still subsystem-specific exits.
	exitReason := ""
	setExit := func(condition, reason string) {
		exitReason = reason
		result.StopCondition = condition
		result.ExitReason = reason
	}

	emit("loop.start", map[string]any{
		"worker_id":    runtime.WorkerID,
		"project_root": runtime.ProjectRoot,
		"harness":      harness,
		"model":        model,
		"session_id":   runtime.SessionID,
		"assignee":     assignee,
		"mode":         string(loopMode),
		"once":         loopMode == executeloop.ModeOnce,
	})
	cleanupLog := runtime.CleanupLog
	if cleanupLog == nil {
		cleanupLog = runtime.Log
	}
	cleanupStop := startExecutionCleanupWorker(ctx, runtime.ProjectRoot, runtime.CleanupRunner, runtime.CleanupInterval, runtime.CleanupTickCh, cleanupLog, emit)
	attemptStarted := false
	defer func() {
		cleanupStop(ctx.Err() != nil && attemptStarted)
	}()
	_, _, _ = runExecutionCleanupPass(ctx, runtime.ProjectRoot, runtime.CleanupRunner, cleanupLog, emit, "startup")
	leaseReader, _ := w.Store.(orphanHarnessLeaseReader)
	releaser, _ := w.Store.(orphanHarnessLeaseReleaser)
	appender, _ := w.Store.(orphanHarnessEventAppender)
	if reaped, reapErr := reapOrphanedHarnessChildren(
		ctx,
		runtime.ProjectRoot,
		newOrphanHarnessProcessScanner(),
		leaseReader,
		releaser,
		appender,
		assignee,
		runtime.Log,
		emit,
		func(pid int) error { return killProcessGroup(pid) },
	); reapErr != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "startup orphan harness reaper failed: %v\n", reapErr)
		}
		emit("loop.operator_attention", map[string]any{
			"reason":       "orphan_harness_reaper_failed",
			"project_root": runtime.ProjectRoot,
			"error":        reapErr.Error(),
		})
	} else if reaped > 0 && runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "startup orphan harness reaper killed %d orphaned harness process(es)\n", reaped)
	}
	if runtime.RoutePreflight != nil {
		routeTimeout := runtime.effectiveRouteResolutionTimeout()
		rerr, timedOut := runRoutePreflightBounded(ctx, routeTimeout, func(c context.Context) error {
			return runtime.RoutePreflight(c, harness, model)
		})
		if timedOut {
			// Slow-but-live resolver: no bead lease is held at startup so there
			// is nothing to release. Log, emit a non-fatal warning, and continue
			// into the drain loop — the next claim iteration calls RoutePreflight
			// again, giving a slow resolver another window to succeed (D1c).
			detail := fmt.Sprintf("routing preflight timed out after %s (harness=%s model=%s); no lease held — continuing",
				routeTimeout, harness, model)
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "routing preflight: %s\n", detail)
			}
			emit("loop.warn", map[string]any{
				"reason":  "startup_route_preflight_timeout",
				"harness": harness,
				"model":   model,
				"timeout": routeTimeout.String(),
				"detail":  detail,
			})
		} else if rerr != nil {
			detail := fmt.Sprintf("routing preflight rejected (harness=%s model=%s): %s",
				harness, model, rerr.Error())
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "routing preflight: %s (startup)\n", detail)
			}
			emit("preflight.rejected", map[string]any{
				"harness": harness,
				"model":   model,
				"reason":  rerr.Error(),
				"startup": true,
			})
			report := ExecuteBeadReport{
				Status:           ExecuteBeadStatusExecutionFailed,
				Detail:           detail,
				Harness:          harness,
				Model:            model,
				Disrupted:        true,
				DisruptionReason: "preflight_rejected",
				OutcomeReason:    "preflight_failed",
			}
			emitDisruptionDetected(emit, w.Store, "", "preflight_rejected", detail, harness, model, assignee, now().UTC())
			result.Failures++
			result.LastFailureStatus = report.Status
			result.Results = append(result.Results, report)
			setExit("Preflight", "preflight_failed")
			return result, nil
		}
	}
	defer func() {
		emit("loop.end", map[string]any{
			"attempts":            result.Attempts,
			"successes":           result.Successes,
			"failures":            result.Failures,
			"last_failure_status": result.LastFailureStatus,
			"exit_reason":         exitReason,
		})
	}()

	state := &executeBeadLoopState{
		now:                        now,
		assignee:                   assignee,
		preClaimTimeout:            preClaimTimeout,
		noProgressCooldown:         noProgressCooldown,
		heartbeatInterval:          heartbeatInterval,
		harness:                    harness,
		provider:                   provider,
		model:                      model,
		profile:                    profile,
		loopMode:                   loopMode,
		idleInterval:               idleInterval,
		result:                     result,
		resultsResetIdx:            resultsResetIdx,
		transientCandidateSkips:    transientCandidateSkips,
		pausedInfraUntil:           pausedInfraUntil,
		complexityGuard:            complexityGuard,
		preclaimGuard:              preclaimGuard,
		workLog:                    workLog,
		wasIdle:                    wasIdle,
		lastIdleQueueSignature:     lastIdleQueueSignature,
		preClaimIdleDetail:         preClaimIdleDetail,
		preClaimIdleStreak:         preClaimIdleStreak,
		preClaimIdleFirstAt:        preClaimIdleFirstAt,
		preClaimIdleEscalated:      preClaimIdleEscalated,
		liveness:                   liveness,
		serverOutage:               serverOutage,
		serverUnavailableLogged:    serverUnavailableLogged,
		sawParentBackEdge:          sawParentBackEdge,
		claimSuccessRateWindowSize: claimSuccessRateWindowSize,
		claimSuccessRateThreshold:  claimSuccessRateThreshold,
		claimSuccessRateWindow:     claimSuccessRateWindow,
		claimSuccessRateSuccesses:  claimSuccessRateSuccesses,
		claimSuccessRateWarned:     claimSuccessRateWarned,
		preClaimWarnThreshold:      preClaimWarnThreshold,
		preClaimWarnState:          preClaimWarnState,
		exitReason:                 exitReason,
		cleanupLog:                 cleanupLog,
		attemptStarted:             &attemptStarted,
	}
	for {
		outcome, err := w.runIteration(ctx, rcfg, runtime, state)
		exitReason = state.exitReason
		if err != nil {
			return result, err
		}
		if outcome.Stop {
			return result, nil
		}
	}
}

func (w *ExecuteBeadWorker) runIteration(ctx context.Context, rcfg config.ResolvedConfig, runtime ExecuteBeadLoopRuntime, state *executeBeadLoopState) (executeBeadIterationOutcome, error) {
	now := state.now
	assignee := state.assignee
	preClaimTimeout := state.preClaimTimeout
	noProgressCooldown := state.noProgressCooldown
	heartbeatInterval := state.heartbeatInterval
	harness := state.harness
	provider := state.provider
	model := state.model
	profile := state.profile
	loopMode := state.loopMode
	idleInterval := state.idleInterval
	result := state.result
	resultsResetIdx := state.resultsResetIdx
	transientCandidateSkips := state.transientCandidateSkips
	pausedInfraUntil := state.pausedInfraUntil
	complexityGuard := state.complexityGuard
	preclaimGuard := state.preclaimGuard
	workLog := state.workLog
	wasIdle := state.wasIdle
	lastIdleQueueSignature := state.lastIdleQueueSignature
	preClaimIdleDetail := state.preClaimIdleDetail
	preClaimIdleStreak := state.preClaimIdleStreak
	preClaimIdleFirstAt := state.preClaimIdleFirstAt
	preClaimIdleEscalated := state.preClaimIdleEscalated
	liveness := state.liveness
	serverOutage := state.serverOutage
	serverUnavailableLogged := state.serverUnavailableLogged
	sawParentBackEdge := state.sawParentBackEdge
	claimSuccessRateWindowSize := state.claimSuccessRateWindowSize
	claimSuccessRateThreshold := state.claimSuccessRateThreshold
	claimSuccessRateWindow := state.claimSuccessRateWindow
	claimSuccessRateSuccesses := state.claimSuccessRateSuccesses
	claimSuccessRateWarned := state.claimSuccessRateWarned
	preClaimWarnThreshold := state.preClaimWarnThreshold
	preClaimWarnState := state.preClaimWarnState
	exitReason := state.exitReason
	cleanupLog := state.cleanupLog
	attemptStarted := false
	if state.attemptStarted != nil {
		attemptStarted = *state.attemptStarted
	}
	defer func() {
		state.resultsResetIdx = resultsResetIdx
		state.pausedInfraUntil = pausedInfraUntil
		state.workLog = workLog
		state.wasIdle = wasIdle
		state.lastIdleQueueSignature = lastIdleQueueSignature
		state.preClaimIdleDetail = preClaimIdleDetail
		state.preClaimIdleStreak = preClaimIdleStreak
		state.preClaimIdleFirstAt = preClaimIdleFirstAt
		state.preClaimIdleEscalated = preClaimIdleEscalated
		state.serverUnavailableLogged = serverUnavailableLogged
		state.sawParentBackEdge = sawParentBackEdge
		state.claimSuccessRateWindow = claimSuccessRateWindow
		state.claimSuccessRateSuccesses = claimSuccessRateSuccesses
		state.claimSuccessRateWarned = claimSuccessRateWarned
		state.preClaimWarnState = preClaimWarnState
		state.exitReason = exitReason
		if state.attemptStarted != nil {
			*state.attemptStarted = attemptStarted
		}
	}()

	setExit := func(condition, reason string) {
		exitReason = reason
		result.StopCondition = condition
		result.ExitReason = reason
	}
	applyStop := func(input work.StopInput) bool {
		decision, ok := work.ClassifyStop(input)
		if !ok {
			return false
		}
		setExit(string(decision.Condition), decision.ExitReason)
		return true
	}
	resetPreClaimIdleStreak := func() {
		preClaimIdleDetail = ""
		preClaimIdleStreak = 0
		preClaimIdleEscalated = false
	}
	setServerUnavailableState := func(at time.Time) {
		if liveness == nil {
			return
		}
		liveness.SetWorkerState(serverUnavailableStatePhase, serverUnavailableLogMessage)
		liveness.OnTick(at)
	}
	clearServerUnavailableState := func(at time.Time) {
		if liveness == nil {
			return
		}
		liveness.SetWorkerState("", "")
		liveness.OnTick(at)
	}
	emit := func(eventType string, data map[string]any) {
		writeLoopEvent(runtime.EventSink, runtime.SessionID, eventType, data, now().UTC())
	}
	appendPreClaimWarn := func(beadID, reason, detail string, at time.Time) bool {
		escalated := appendPreClaimIntakeWarning(w.Store, emit, &preClaimWarnState, preClaimWarnThreshold, beadID, assignee, reason, detail, at)
		if !escalated {
			return false
		}
		detailText := fmt.Sprintf(
			"pre-claim warn fingerprint repeated %d times across %d distinct bead IDs",
			preClaimWarnState.Count,
			len(preClaimWarnState.DistinctBeadIDs),
		)
		result.OperatorAttention = &OperatorAttentionStop{
			Reason:      "preclaim_warn_repeated",
			BeadID:      beadID,
			ProjectRoot: runtime.ProjectRoot,
			Message:     detailText,
		}
		setExit("OperatorAttention", "operator_attention")
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "operator attention: %s\n", detailText)
		}
		return true
	}
	recordClaimAttempt := func(success bool, beadID string) {
		if claimSuccessRateWindowSize <= 0 {
			return
		}
		if len(claimSuccessRateWindow) == claimSuccessRateWindowSize {
			if claimSuccessRateWindow[0] {
				claimSuccessRateSuccesses--
			}
			copy(claimSuccessRateWindow, claimSuccessRateWindow[1:])
			claimSuccessRateWindow = claimSuccessRateWindow[:claimSuccessRateWindowSize-1]
		}
		claimSuccessRateWindow = append(claimSuccessRateWindow, success)
		if success {
			claimSuccessRateSuccesses++
			claimSuccessRateWarned = false
			return
		}
		if len(claimSuccessRateWindow) < claimSuccessRateWindowSize {
			return
		}
		rate := float64(claimSuccessRateSuccesses) / float64(claimSuccessRateWindowSize)
		if rate > claimSuccessRateThreshold || claimSuccessRateWarned {
			return
		}
		claimSuccessRateWarned = true
		detail := fmt.Sprintf(
			"claim success rate %.3f over the last %d claim attempts (%d successes, %d non-successes) is at or below threshold %.3f; manual intervention may be required",
			rate,
			claimSuccessRateWindowSize,
			claimSuccessRateSuccesses,
			claimSuccessRateWindowSize-claimSuccessRateSuccesses,
			claimSuccessRateThreshold,
		)
		emit("loop.operator_attention", map[string]any{
			"reason":        "claim_success_rate_below_threshold",
			"bead_id":       beadID,
			"detail":        detail,
			"window_size":   claimSuccessRateWindowSize,
			"successes":     claimSuccessRateSuccesses,
			"non_successes": claimSuccessRateWindowSize - claimSuccessRateSuccesses,
			"success_rate":  rate,
			"threshold":     claimSuccessRateThreshold,
		})
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "operator attention: %s\n", detail)
		}
	}
	clearTransientCandidateSkips := func() {
		for beadID := range transientCandidateSkips {
			delete(transientCandidateSkips, beadID)
		}
	}
	stopAfterNonAttemptSkip := func() bool {
		return loopMode == executeloop.ModeOnce && runtime.TargetBeadID != ""
	}
	strictIntakeBlocking := func() bool {
		return runtime.TargetBeadID != ""
	}
	finalizeDurableAuditOrStop := func(candidateID string, report ExecuteBeadReport) bool {
		if runtime.FinalizeDurableAudit == nil {
			return false
		}
		if err := runtime.FinalizeDurableAudit(report); err != nil {
			// Transient .git/index.lock contention from concurrent workers must
			// not stop the drain (ddx-23ac2796). The pending tracker/audit
			// changes remain staged and are committed on a later iteration, so
			// treat lock contention as retryable rather than operator attention --
			// a transient lock conflict must never halt an unattended worker.
			if isTransientGitContention(err) {
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log,
						"transient git/tracker contention committing durable audit outputs for %s; not stopping (will retry next iteration): %v\n",
						candidateID, err)
				}
				emit("loop.durable_audit_transient", map[string]any{
					"reason":  "git_tracker_contention",
					"bead_id": candidateID,
					"detail":  strings.TrimSpace(err.Error()),
				})
				return false
			}
			projectRoot := strings.TrimSpace(firstNonEmpty(report.ProjectRoot, runtime.ProjectRoot))
			dirtyPaths := append([]string(nil), trackerpaths.ManagedPathspecs()...)
			result.OperatorAttention = &OperatorAttentionStop{
				Reason:      "durable_audit_commit_failed",
				BeadID:      candidateID,
				ProjectRoot: projectRoot,
				DirtyPaths:  dirtyPaths,
				Message:     "DDx could not commit durable audit outputs; resolve the git failure before continuing autonomous work.",
			}
			setExit("OperatorAttention", "operator_attention")
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log,
					"operator attention: failed to commit durable audit outputs for %s; stopping work. %v\n",
					candidateID,
					err,
				)
			}
			emit("loop.operator_attention", map[string]any{
				"reason":       "durable_audit_commit_failed",
				"bead_id":      candidateID,
				"project_root": projectRoot,
				"dirty_paths":  dirtyPaths,
				"message":      result.OperatorAttention.Message,
				"detail":       strings.TrimSpace(err.Error()),
			})
			return true
		}
		return false
	}
	_, _, _ = runExecutionCleanupPass(ctx, runtime.ProjectRoot, runtime.CleanupRunner, cleanupLog, emit, "pre-claim")
	// Respect context cancellation between iterations. Without this check,
	// a Stop() request (which cancels ctx) would only take effect during
	// the idle poll sleep — the loop would happily claim the next ready
	// bead as soon as the current Execute returned, ignoring the cancel.
	if err := ctx.Err(); err != nil {
		if exitReason == "" {
			applyStop(work.StopInput{ContextErr: err})
		}
		return executeBeadIterationOutcome{Stop: true}, err
	}
	if loopMode == executeloop.ModeWatch && serverOutage.Active() {
		if !serverUnavailableLogged && runtime.Log != nil {
			_, _ = fmt.Fprintln(runtime.Log, serverUnavailableLogMessage)
			serverUnavailableLogged = true
		}
		setServerUnavailableState(now().UTC())
		for serverOutage.Active() {
			delay := time.Until(serverOutage.NextProbeAt())
			if delay < 0 {
				delay = 0
			}
			if err := sleepOrWake(ctx, delay, runtime.WakeCh); err != nil {
				if exitReason == "" {
					applyStop(work.StopInput{ContextErr: err})
				}
				return executeBeadIterationOutcome{Stop: true}, err
			}
			probeAt := now().UTC()
			setServerUnavailableState(probeAt)
			healthy := false
			var probeErr error
			if runtime.ServerHealthProbe != nil {
				healthy, probeErr = runtime.ServerHealthProbe(ctx)
				if probeErr != nil && runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "server health probe failed: %v (retrying)\n", probeErr)
				}
			}
			serverOutage.MarkProbeAttempt(probeAt)
			if healthy {
				reason := serverOutage.Reason()
				serverOutage.Clear()
				clearServerUnavailableState(now().UTC())
				serverUnavailableLogged = false
				emit("loop.server_recovered", map[string]any{
					"reason": reason,
				})
				if runtime.Log != nil {
					_, _ = fmt.Fprintln(runtime.Log, "server reachable: resuming queue")
				}
				break
			}

package cmd

import (
	"encoding/json"
	"fmt"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/spf13/cobra"
)

type cleanupCommandReport struct {
	DryRun                      bool                                   `json:"dry_run"`
	ProjectRoot                 string                                 `json:"project_root"`
	TempRoot                    string                                 `json:"temp_root"`
	ScannedTempDirs             int                                    `json:"scanned_temp_dirs"`
	ScannedEvidenceDirs         int                                    `json:"scanned_evidence_dirs"`
	CompleteEvidenceDirs        int                                    `json:"complete_evidence_dirs"`
	ScannedScratchDirs          int                                    `json:"scanned_scratch_dirs"`
	RemovedUnregisteredTempDirs int64                                  `json:"removed_unregistered_temp_dirs"`
	RemovedRegisteredWorktrees  int64                                  `json:"removed_registered_worktrees"`
	RemovedRunStateFiles        int64                                  `json:"removed_run_state_files"`
	RemovedScratchDirs          int64                                  `json:"removed_scratch_dirs"`
	PreservedActiveScratchDirs  int64                                  `json:"preserved_active_scratch_dirs"`
	BytesReclaimed              int64                                  `json:"bytes_reclaimed"`
	InodesReclaimed             int64                                  `json:"inodes_reclaimed"`
	ScratchBytesReclaimed       int64                                  `json:"scratch_bytes_reclaimed"`
	ScratchInodesReclaimed      int64                                  `json:"scratch_inodes_reclaimed"`
	Warnings                    []agent.ExecutionCleanupWarning        `json:"warnings"`
	BlockedErrors               []agent.ExecutionCleanupIssue          `json:"blocked_errors"`
	Observations                []agent.ExecutionCleanupObservation    `json:"observations"`
	ProcessFindingsCount        int                                    `json:"process_findings_count"`
	StaleProcessGroups          int                                    `json:"stale_process_groups"`
	TerminatedProcessGroups     int                                    `json:"terminated_process_groups"`
	ProcessFindings             []agent.ExecutionCleanupProcessFinding `json:"process_findings"`
}

func (f *CommandFactory) newCleanupCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "cleanup",
		Short: "Inspect and clean stale DDx execution resources",
		Long: `Inspect DDx-owned execution resources and conservatively clean stale state.

By default, cleanup runs in dry-run mode and reports what it would remove.
Use --apply to remove stale DDx temp worktrees, stale run-state files, and
other DDx-owned scratch resources under the configured project roots.

Examples:
  ddx cleanup
  ddx cleanup --json
  ddx cleanup --apply
  ddx cleanup --project /path/to/project --apply`,
		Args: cobra.NoArgs,
		RunE: f.runCleanup,
	}

	cmd.Flags().Bool("apply", false, "Actually remove stale DDx execution resources")
	cmd.Flags().Bool("json", false, "Output the cleanup report as JSON")
	cmd.Flags().String("project", "", "Project root to inspect (default: detected from CWD)")
	return cmd
}

func (f *CommandFactory) runCleanup(cmd *cobra.Command, args []string) error {
	_ = args
	projectFlag, _ := cmd.Flags().GetString("project")
	apply, _ := cmd.Flags().GetBool("apply")
	asJSON, _ := cmd.Flags().GetBool("json")

	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	if projectRoot == "" {
		projectRoot = f.WorkingDir
	}

	mgr := agent.NewExecutionCleanupManager(projectRoot, &agent.RealGitOps{})
	mgr.DryRun = !apply

	summary, err := mgr.Cleanup(cmd.Context())
	if err != nil {
		return err
	}

	report := cleanupCommandReport{
		DryRun:                      !apply,
		ProjectRoot:                 summary.ProjectRoot,
		TempRoot:                    summary.TempRoot,
		ScannedTempDirs:             summary.ScannedTempDirs,
		ScannedEvidenceDirs:         summary.ScannedEvidenceDirs,
		CompleteEvidenceDirs:        summary.CompleteEvidenceDirs,
		ScannedScratchDirs:          summary.ScannedScratchDirs,
		RemovedUnregisteredTempDirs: summary.RemovedUnregisteredTempDirs,
		RemovedRegisteredWorktrees:  summary.RemovedRegisteredWorktrees,
		RemovedRunStateFiles:        summary.RemovedRunStateFiles,
		RemovedScratchDirs:          summary.RemovedScratchDirs,
		PreservedActiveScratchDirs:  summary.PreservedActiveScratchDirs,
		BytesReclaimed:              summary.BytesReclaimed,
		InodesReclaimed:             summary.InodesReclaimed,
		ScratchBytesReclaimed:       summary.ScratchBytesReclaimed,
		ScratchInodesReclaimed:      summary.ScratchInodesReclaimed,
		Warnings:                    append([]agent.ExecutionCleanupWarning(nil), summary.Warnings...),
		Observations:                append([]agent.ExecutionCleanupObservation(nil), summary.Observations...),
		ProcessFindings:             append([]agent.ExecutionCleanupProcessFinding(nil), summary.ProcessFindings...),
	}
	for _, issue := range summary.Issues {
		if issue.Blocking {
			report.BlockedErrors = append(report.BlockedErrors, issue)
		}
	}
	for _, finding := range report.ProcessFindings {
		report.ProcessFindingsCount++
		if finding.WouldKill {
			report.StaleProcessGroups++
		}
		if finding.Terminated {
			report.TerminatedProcessGroups++
		}
	}
	if report.Warnings == nil {
		report.Warnings = []agent.ExecutionCleanupWarning{}
	}
	if report.BlockedErrors == nil {
		report.BlockedErrors = []agent.ExecutionCleanupIssue{}
	}
	if report.Observations == nil {
		report.Observations = []agent.ExecutionCleanupObservation{}
	}
	if report.ProcessFindings == nil {
		report.ProcessFindings = []agent.ExecutionCleanupProcessFinding{}
	}

	if asJSON {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(report)
	}

	out := cmd.OutOrStdout()
	verb := "removed"
	if report.DryRun {
		verb = "would remove"
	}
	fmt.Fprintf(out, "cleanup: %s %d stale temp dir(s), %d registered worktree(s), %d run-state file(s), %d scratch dir(s)\n",
		verb,
		report.RemovedUnregisteredTempDirs,
		report.RemovedRegisteredWorktrees,
		report.RemovedRunStateFiles,
		report.RemovedScratchDirs,
	)
	if report.BytesReclaimed > 0 || report.InodesReclaimed > 0 {
		fmt.Fprintf(out, "cleanup: %s %d byte(s), %d inode(s)\n", verb, report.BytesReclaimed, report.InodesReclaimed)
	}
	if report.ScratchBytesReclaimed > 0 || report.ScratchInodesReclaimed > 0 || report.PreservedActiveScratchDirs > 0 {
		fmt.Fprintf(out, "cleanup: scratch scope %s %d byte(s), %d inode(s); preserved %d active scratch dir(s)\n",
			verb,
			report.ScratchBytesReclaimed,
			report.ScratchInodesReclaimed,
			report.PreservedActiveScratchDirs,
		)
	}
	if report.CompleteEvidenceDirs > 0 {
		fmt.Fprintf(out, "cleanup: preserved %d complete evidence bundle(s)\n", report.CompleteEvidenceDirs)
	}
	if report.StaleProcessGroups > 0 {
		if report.DryRun {
			fmt.Fprintf(out, "cleanup: found %d stale process group(s) (would kill: %d)\n", report.StaleProcessGroups, report.StaleProcessGroups)
		} else {
			fmt.Fprintf(out, "cleanup: found %d stale process group(s) (killed: %d)\n", report.StaleProcessGroups, report.TerminatedProcessGroups)
		}
		for _, f := range report.ProcessFindings {
			if f.PID > 0 {
				fmt.Fprintf(out, "  stale process: pid=%d pgid=%d command=%q worktree=%s reason=%s\n",
					f.PID, f.PGID, f.Command, f.Worktree, f.StaleReason)
			}
		}
	}
	for _, warning := range report.Warnings {
		fmt.Fprintf(out, "warning: %s (%s): %s\n", warning.Path, warning.Class, warning.Message)
	}
	for _, issue := range report.BlockedErrors {
		fmt.Fprintf(out, "blocked: %s (%s): %s\n", issue.Path, issue.Class, issue.Message)
	}
	if report.DryRun {
		fmt.Fprintln(out, "run again with --apply to remove these resources")
	}
	return nil
}

